#include <stdio.h>
#include <math.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long root = (long long) sqrt((double) N);
        long long d = 1;
        for (long long i = root; i >= 1; --i) {
            if (N % i == 0) { d = i; break; }
        }
        long long diff = (N / d) - d;
        printf("%lld\n", diff);
    }
    return 0;
}

