import sys, math

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        root = int(math.isqrt(N))
        d = 1
        for i in range(root, 0, -1):
            if N % i == 0:
                d = i
                break
        out.append(str(N // d - d))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

